#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        int X,Y; scanf("%d %d",&X,&Y);
        char s[105];
        for(int i=0;i<N;i++){
            scanf("%s",s);
            int full=0, part=0;
            for(int j=0;j<M;j++){
                if(s[j]=='F') full++;
                else if(s[j]=='P') part++;
            }
            if(full>=X || (full>=X-1 && part>=Y)) putchar('1');
            else putchar('0');
        }
        putchar('\n');
    }
    return 0;
}

